## 10.  Putting It All Together – A Mini “Obfuscated Kext” Skeleton

```c
/* obf_kext.c – a teaching example that combines several tricks   */
#include <IOKit/IOLib.h>
#include <IOKit/IOService.h>
#include <mach/mach_time.h>
#include <sys/kdebug.h>

extern const uint8_t __start___OBF[];
extern const uint8_t __stop___OBF[];

static const uint8_t xor_key = 0x6D;

/* ---------- 1. anti‑debug ----------------------------------- */
static inline bool debugger_present(void)
{
    return (kdebug_enable != 0);
}

/* ---------- 2. runtime unpacker ----------------------------- */
static void *unpacked = NULL;
static size_t unpacked_len = 0;

static kern_return_t unpack_self(void)
{
    unpacked_len = __stop___OBF - __start___OBF;
    vm_offset_t addr = 0;
    kern_return_t kr = kmem_alloc(kernel_map, &addr, unpacked_len);
    if (kr != KERN_SUCCESS) return kr;
    vm_protect(kernel_map, addr, unpacked_len,
               FALSE, VM_PROT_READ|VM_PROT_WRITE|VM_PROT_EXECUTE);
    bcopy(__start___OBF, (void *)addr, unpacked_len);
    uint8_t *p = (uint8_t *)addr;
    for (size_t i = 0; i < unpacked_len; ++i) p[i] ^= xor_key;
    unpacked = (void *)addr;
    return KERN_SUCCESS;
}

/* ---------- 3. flattened dispatcher ------------------------ */
typedef IOReturn (*state_fn_t)(void *);
static IOReturn state_A(void *);
static IOReturn state_B(void *);
static IOReturn state_C(void *);
static IOReturn state_DONE(void *);

static const state_fn_t state_tbl[] = { state_DONE, state_C, state_B, state_A };

static IOReturn flattened(void)
{
    uint32_t st = 3;   // start at A
    while (st != 0) {
        st = (uint32_t)(*state_tbl[st])(&st);
    }
    return kIOReturnSuccess;
}

/* Minimal workers – each returns the index of the next state */
static IOReturn state_A(void *ctx) { IOLog("A\n"); return 2; }
static IOReturn state_B(void *ctx) { IOLog("B\n"); return 2; }
static IOReturn state_C(void *ctx) { IOLog("C\n"); return 0; }
static IOReturn state_DONE(void *ctx) { return 0; }

/* ---------- 4. start routine -------------------------------- */
extern "C" kern_return_t _kext_9a7b3c4d(void)   // random export name
{
    if (debugger_present()) {
        IOLog("[!] Debugger detected – refusing to run.\n");
        return KERN_FAILURE;
    }
    if (unpack_self() != KERN_SUCCESS) {
        IOLog("Failed to unpack payload.\n");
        return KERN_FAILURE;
    }
    /* Jump into the unpacked payload (which in this demo simply calls
     * the flattened dispatcher). */
    typedef IOReturn (*payload_t)(void);
    payload_t payload = (payload_t)unpacked;
    return payload();               // runs flattened()
}
```

*What you see:*  

* A **randomly‑named exported symbol** (`_kext_9a7b3c4d`).  
* An **anti‑debug check** that aborts early.  
* **Self‑unpacking** of a blob stored in a custom `__OBF` section, decrypted with XOR.  
* The **unpacked blob** contains a **flattened state machine** (the `flattened()` function).  

All the concepts above can be mixed, layered and expanded (e.g., add opaque predicates inside each state, encrypt the state table, patch the `flattened` function after a licence check, etc.).  

